USE webApi_flutter_test;

-- 1) Nettoyage de l'ancien seed synthétique
DELETE FROM F_LIVRAISON WHERE DO_Piece LIKE 'BCAI%' OR DO_Piece LIKE 'BCEX%';
DELETE FROM F_DOCENTETE WHERE DO_Piece LIKE 'BCAI%' OR DO_Piece LIKE 'BCEX%';
DELETE FROM ProfilsUtilisateurs WHERE CodeClientSage LIKE 'CLAI%' OR CodeClientSage LIKE 'CLEX%';
