-- 5) Diagnostic ML.NET
PRINT '';
PRINT '--- Diagnostic ML.NET (après seed réel) ---';
SELECT 'Total commandes (DO_Domaine=0, DO_Type=0)' AS Indicator, COUNT(*) AS Value FROM F_DOCENTETE WHERE DO_Domaine=0 AND DO_Type=0;
SELECT 'Cmd avec livraison' AS Indicator, COUNT(*) AS Value FROM F_DOCENTETE o INNER JOIN F_LIVRAISON l ON l.DO_Piece = o.DO_Piece WHERE o.DO_Domaine=0 AND o.DO_Type=0;
SELECT 'Jours distincts' AS Indicator, COUNT(DISTINCT CAST(DO_Date AS DATE)) AS Value FROM F_DOCENTETE WHERE DO_Domaine=0 AND DO_Type=0;
SELECT LI_Statut, CASE LI_Statut WHEN 1 THEN 'EnLivraison' WHEN 2 THEN 'Livre' WHEN 3 THEN 'Retour' END AS Label, COUNT(*) AS NbLivraisons FROM F_LIVRAISON GROUP BY LI_Statut ORDER BY LI_Statut;
SELECT TOP 10 p.Gouvernorat, COUNT(o.cbMarq) AS NbCommandes, SUM(CASE WHEN l.LI_Statut=3 THEN 1 ELSE 0 END) AS NbRetours FROM ProfilsUtilisateurs p LEFT JOIN F_DOCENTETE o ON o.DO_Tiers = p.CodeClientSage LEFT JOIN F_LIVRAISON l ON l.DO_Piece = o.DO_Piece WHERE p.CodeClientSage LIKE 'CLEX%' GROUP BY p.Gouvernorat ORDER BY NbCommandes DESC;
